CREATE TABLE IF NOT EXISTS `inventory_item_allowed_households` (
  `id` int AUTO_INCREMENT NOT NULL,
  `inventoryItemId` int NOT NULL,
  `allowedHouseholdId` int NOT NULL,
  `createdAt` timestamp NOT NULL DEFAULT (now()),
  CONSTRAINT `iiah_id` PRIMARY KEY(`id`),
  CONSTRAINT `iiah_item_fk` FOREIGN KEY (`inventoryItemId`) REFERENCES `inventory_items`(`id`) ON DELETE cascade,
  CONSTRAINT `iiah_household_fk` FOREIGN KEY (`allowedHouseholdId`) REFERENCES `households`(`id`) ON DELETE cascade
);

ALTER TABLE `inventory_items` ADD COLUMN IF NOT EXISTS `visibility` enum('private','connected','selected') DEFAULT 'private' NOT NULL;
